using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json.Serialization;
using ModelContextProtocol.Server;

namespace McpServer;

/// <summary>
/// Each public method decorated with [McpServerTool] becomes a tool the LLM can invoke.
/// The class is instantiated per-call via DI — constructor parameters are resolved from
/// the service container, and method parameters are populated from the MCP request.
/// </summary>
[McpServerToolType]
public class WeatherTools
{
    private readonly HttpClient _http;

    // Constructor-injected HttpClient (resolved via DI / IHttpClientFactory)
    public WeatherTools(HttpClient http)
    {
        _http = http;
    }

    [McpServerTool(Name = "get_weather")]
    [Description("Gets current weather for a city using the Open-Meteo API (no API key needed).")]
    public async Task<string> GetWeatherAsync(
        [Description("Latitude of the location")] double latitude,
        [Description("Longitude of the location")] double longitude,
        CancellationToken cancellationToken = default)
    {
        var url = $"https://api.open-meteo.com/v1/forecast" +
                  $"?latitude={latitude}&longitude={longitude}" +
                  $"&current=temperature_2m,wind_speed_10m";

        var response = await _http.GetFromJsonAsync<WeatherResponse>(url, cancellationToken);

        if (response?.Current is null)
            return "No weather data available for that location.";

        var c = response.Current;
        return $"Temperature: {c.Temperature}°C, Wind: {c.WindSpeed} km/h";
    }

    [McpServerTool(Name = "geocode_city")]
    [Description("Converts a city name to latitude/longitude coordinates.")]
    public async Task<string> GeocodeCityAsync(
        [Description("City name to look up, e.g. 'London'")] string city,
        CancellationToken cancellationToken = default)
    {
        var url = $"https://geocoding-api.open-meteo.com/v1/search?name={Uri.EscapeDataString(city)}&count=1";
        var response = await _http.GetFromJsonAsync<GeocodeResponse>(url, cancellationToken);

        if (response?.Results is not { Count: > 0 })
            return $"Could not find coordinates for '{city}'.";

        var r = response.Results[0];
        return $"{r.Name} ({r.Country}): lat={r.Latitude}, lon={r.Longitude}";
    }
}

// --- DTOs for the Open-Meteo API ---

public record WeatherResponse(
    [property: JsonPropertyName("current")] CurrentWeather? Current);

public record CurrentWeather(
    [property: JsonPropertyName("temperature_2m")] double Temperature,
    [property: JsonPropertyName("wind_speed_10m")] double WindSpeed);

public record GeocodeResponse(
    [property: JsonPropertyName("results")] List<GeocodeResult>? Results);

public record GeocodeResult(
    [property: JsonPropertyName("name")] string Name,
    [property: JsonPropertyName("country")] string Country,
    [property: JsonPropertyName("latitude")] double Latitude,
    [property: JsonPropertyName("longitude")] double Longitude);

